// Parse incoming response from SmartLead webhook
const items = $input.all();
const results = [];

for (const item of items) {
  const data = item.json.body || item.json;

  results.push({
    json: {
      // Response data
      from_email: data.from_email || data.email || data.lead_email || '',
      from_name: data.from_name || data.lead_name || '',
      company_name: data.company_name || '',
      subject: data.subject || '',
      body: data.body || data.text || data.message || '',
      reply_date: data.reply_date || data.received_at || new Date().toISOString(),

      // Campaign context
      campaign_id: data.campaign_id || '',
      sequence_id: data.sequence_id || '',
      lead_id: data.lead_id || '',

      // Raw payload for debugging
      raw_webhook: data
    }
  });
}

return results;

// Parse classification and determine actions
const items = $input.all();
const responses = $('Parse Response').all();
const staticData = $getWorkflowStaticData('global');
staticData.respondedCompanies = staticData.respondedCompanies || {};

const results = [];

for (let i = 0; i < items.length; i++) {
  const response = items[i].json;
  const originalResponse = responses[i]?.json || {};
  const content = response.content?.[0]?.text || '';

  let classification = {};
  try {
    const jsonMatch = content.match(/\{[\s\S]*\}/);
    if (jsonMatch) classification = JSON.parse(jsonMatch[0]);
  } catch (e) {
    classification = { category: 'POSITIVE', sentiment_score: 5, summary: 'Classification failed', urgency: 'medium' };
  }

  const company = originalResponse.company_name?.toLowerCase() || '';

  // CRITICAL: If ANY response from this company, stop all other sequences
  if (['POSITIVE', 'REFERRAL', 'NOT_NOW', 'OBJECTION', 'NEGATIVE'].includes(classification.category)) {
    staticData.respondedCompanies[company] = originalResponse.from_email;
  }

  results.push({
    json: {
      ...originalResponse,
      classification: classification.category,
      sentiment_score: classification.sentiment_score,
      summary: classification.summary,
      suggested_action: classification.suggested_action,
      urgency: classification.urgency,
      referred_to: classification.referred_to,
      company_sequences_stopped: ['POSITIVE', 'REFERRAL', 'NOT_NOW', 'OBJECTION', 'NEGATIVE'].includes(classification.category),
      processed_at: new Date().toISOString()
    }
  });
}

return results;

// Stop all sequences for this company in SmartLead
const items = $input.all();
return items.filter(i => i.json.company_sequences_stopped).map(item => ({
  json: {
    company_name: item.json.company_name,
    responded_by: item.json.from_email,
    action: 'stop_company_sequences'
  }
}));

// Handle referrals - add new contact to pipeline
const items = $input.all();
return items.filter(i => i.json.referred_to).map(item => ({
  json: {
    referred_by: item.json.from_name,
    referred_contact: item.json.referred_to,
    company_name: item.json.company_name,
    source: 'referral',
    priority_tier: 'A',
    pipeline_stage: 'referral_received'
  }
}));
